example.code:
# Django: use Redis session backend
# settings.py
SESSION_ENGINE = "django.contrib.sessions.backends.cache"
SESSION_CACHE_ALIAS = "default"

CACHES = {
    "default": {
        "BACKEND": "django_redis.cache.RedisCache",
        "LOCATION": os.environ["REDIS_URL"],
        "OPTIONS": {"CLIENT_CLASS": "django_redis.client.DefaultClient"},
    }
}
# With this setup: ANY backend can serve ANY request.
# No sticky sessions needed. Auto-scaling works correctly.

upstream api_backend {
    ip_hash;  # WRONG when clients share NAT IPs or autoscaling is active

    server 10.0.1.1:8000;
    server 10.0.1.2:8000;
    server 10.0.1.3:8000;
}
# Corporate office: 500 employees → 1 NAT IP → all traffic to api1
# Mobile: carrier NAT → same problem
# Scale-in event: api1 removed → all ip_hash clients now redistribute
